SELECT /* base.ec.cm :: CmBlogTag :: selectList */ t.* , ste.site_nm AS site_nm FROM cm_blog_tag t LEFT JOIN sy_site ste ON ste.site_id = t.site_id
ORDER BY t.blog_tag_id ASC ORDER BY t.blog_tag_id DESC ORDER BY t.tag_nm ASC ORDER BY t.tag_nm DESC ORDER BY t.reg_date ASC ORDER BY t.reg_date DESC ORDER BY t.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

SELECT /* base.ec.cm :: CmBlogTag :: selectPageList */ t.* , ste.site_nm AS site_nm FROM cm_blog_tag t LEFT JOIN sy_site ste ON ste.site_id = t.site_id
ORDER BY t.blog_tag_id ASC ORDER BY t.blog_tag_id DESC ORDER BY t.tag_nm ASC ORDER BY t.tag_nm DESC ORDER BY t.reg_date ASC ORDER BY t.reg_date DESC ORDER BY t.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE cm_blog_tag /* base.ec.cm :: CmBlogTag :: updateSelective */
site_id = #{siteId}, blog_id = #{blogId}, tag_nm = #{tagNm}, sort_ord = #{sortOrd}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE blog_tag_id = #{blogTagId}
